$body = '{"jsonrpc":"2.0","id":0,"method":"initialize","params":{"protocolVersion":"2024-11-05","capabilities":{},"clientInfo":{"name":"diag","version":"1.0"}}}'
function Test-Mcp($url,$tok){
  Write-Output "===== $url ====="
  try {
    $r = Invoke-WebRequest -Uri $url -Method Post -Headers @{ "Authorization"="Bearer $tok"; "Accept"="application/json, text/event-stream" } -ContentType "application/json" -Body $body -UseBasicParsing -TimeoutSec 20
    Write-Output ("STATUS: " + $r.StatusCode)
    Write-Output ("BODY: " + $r.Content.Substring(0,[Math]::Min(500,$r.Content.Length)))
  } catch {
    $resp = $_.Exception.Response
    if ($resp) {
      Write-Output ("STATUS: " + [int]$resp.StatusCode + " " + $resp.StatusCode)
      $sr = New-Object System.IO.StreamReader($resp.GetResponseStream())
      Write-Output ("BODY: " + $sr.ReadToEnd())
    } else { Write-Output ("ERR: " + $_.Exception.Message) }
  }
}
